// Load script setelah DOM berhasil dimuat
$(function () {
    let $formAddBillboard = $("#formAddBillboard");
    let formCekAddBillboard = FormHelper.cekFormData($formAddBillboard);
    let $formEditBillboard = $("#formEditBillboard");
    let formCekEditBillboard = FormHelper.cekFormData($formEditBillboard);
    let $formUpdateGambarBillboard = $("#formUpdateGambarBillboard");

    let validasiRule = {
        judul: { required: true, minlength: 5, maxlength: 100 },
        area: { required: true, minlength: 5, maxlength: 50 },
        lokasi: { required: true, minlength: 5, maxlength: 255 },
        jenis: { required: true, minlength: 5, maxlength: 100 },

        lebar: { required: true, number: true, min: 1, max: 99 },
        panjang: { required: true, number: true, min: 1, max: 99 },
        unit: { required: true, digits: true, min: 1, max: 99 },

        latitude: { required: true, number: true },
        longitude: { required: true, number: true },

        keterangan: {
            required: function (element) {
                return (
                    $(element)
                        .closest("form")
                        .find('select[name="aktif"]')
                        .val() === "Nonaktif"
                );
            },
            maxlength: 255,
        },
    };

    // Fungsi load statisik billboard
    function loadStats() {}

    /**
     * Fungsi visibilitas keterangan berdasarkan status aktif
     * @param {object} $inputAktif elemen input aktif billboard
     * @param {object} $inputKeterangan elemen keterangan aktif billboard
     */
    function toggleKeterangan($inputAktif, $inputKeterangan) {
        $inputAktif.val() === "Nonaktif"
            ? $inputKeterangan.show()
            : $inputKeterangan.hide();
    }

    // Inisialisasi data tabel billboard-list
    TableHelper.init("#tableBillboardList", {
        ajax: window.routes.dataTable, // Mengambil endpoint url data tabel dari global window variabel
        order: [[1, "asc"]],
        filters: [4, 7], // filter untuk Status & Aktif saja
        buttons: [
            {
                text: "Add",
                attr: {
                    "data-target": "#modalAddBillboard",
                    "data-toggle": "modal",
                },
            },
            { text: "Excel" },
        ],
        columnDefs: [
            { responsivePriority: 1, targets: [1, 4, 5, 7, 3, 8, 9, 0, 11] }, // kolom penting utama
            { responsivePriority: 2, targets: [6] }, // kolom sekunder
            { targets: [10, 12, 13, 14, 15, 16], className: "none" }, // sembunyikan detail
        ],
        columns: [
            {
                data: "id",
                title: "ID",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "judul",
                title: "Judul",
                className: "dt-head-center",
                orderable: true,
            },
            {
                data: "area",
                title: "Area",
                className: "dt-head-center",
                orderable: true,
            },
            {
                data: "lokasi",
                title: "Lokasi",
                className: "dt-head-center",
                orderable: false,
            },
            {
                data: "status",
                title: "Status",
                className: "dt-head-center dt-body-center",
                orderable: true,
                render: function (data, type) {
                    if (type === "display") {
                        return data == 1
                            ? '<span class="lencana bg-success">Tersedia</span>'
                            : '<span class="lencana bg-secondary">Tersewa</span>';
                    }
                    return data == 1 ? "Tersedia" : "Tersewa";
                },
            },
            {
                data: "aktif",
                title: "Aktif",
                className: "dt-head-center dt-body-center col-boolean",
                orderable: true,
                render: function (data, type) {
                    if (type === "display") {
                        return data == 1
                            ? '<span class="lencana bg-primary">Aktif</span>'
                            : '<span class="lencana bg-danger">Nonaktif</span>';
                    }
                    return data == 1 ? "Aktif" : "Nonaktif";
                },
            },
            {
                data: "keterangan",
                title: "Keterangan",
                className: "dt-head-center",
                orderable: true,
            },
            {
                data: "jenis",
                title: "Jenis",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "ukuran",
                title: "Ukuran (m)",
                className: "dt-head-center dt-body-center",
                orderable: false,
            },
            {
                data: "unit",
                title: "Unit",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "koordinat",
                title: "Koordinat",
                className: "dt-head-center dt-body-center",
                orderable: false,
            },
            {
                data: "gambar",
                title: "Gambar",
                className: "dt-head-center dt-body-center dt-gambar",
                orderable: false,
                render: {
                    _: (gambar) => gambar,
                    display: (gambar) =>
                        gambar
                            ? `<img src="/storage/upload/billboard/${gambar}" 
                                        alt="Gambar Billboard" 
                                        class="img-thumbnail rounded shadow-sm billboard-thumb" 
                                        style="width: 100px; height: auto; object-fit: cover;" 
                                        data-full="/storage/upload/billboard/${gambar}"/>`
                            : `<span class="text-muted"></span>`,
                },
            },
            {
                data: "created_at",
                title: "Dibuat",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "updated_at",
                title: "Diubah",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "admin_buat",
                title: "Pembuat",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "admin_ubah",
                title: "Pengubah",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "aksi",
                title: "Aksi",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: (data, type) => (type === "display" ? data : ""),
            },
        ],
    });

    // Ambil billboard berdasarkan id
    $(document).on(
        "click",
        '#tableBillboardList button[data-target="#modalEditBillboard"]',
        function () {
            let id = $(this).data("id");
            let url = window.routes.getBillboard.replace(":id", id); // Mengambil route endpoint yang telah didefinisikan pada global window variabel app.blade.php
            let $form = $("#formEditBillboard");

            $.get(url)
                .done(function (res) {
                    let billboard = res.billboard;

                    $form[0].reset();
                    $form.validate().resetForm();
                    $form
                        .find(".is-valid, .is-invalid")
                        .removeClass("is-valid is-invalid");

                    // Mendefinisikan endpoint route dari global window untuk edit billboard
                    $form.attr(
                        "action",
                        window.routes.updateBillboard.replace(":id", id)
                    );

                    $("#edit_judul").val(billboard.judul);
                    $("#edit_area").val(billboard.area);
                    $("#edit_lokasi").val(billboard.lokasi);
                    $("#edit_jenis").val(billboard.jenis);
                    $("#edit_lebar").val(billboard.lebar);
                    $("#edit_panjang").val(billboard.panjang);
                    $("#edit_unit").val(billboard.unit);
                    $("#edit_latitude").val(billboard.latitude);
                    $("#edit_longitude").val(billboard.longitude);
                    $("#edit_aktif").val(
                        billboard.aktif ? "Aktif" : "Nonaktif"
                    );
                    $("#edit_keterangan").val(billboard.keterangan);

                    // insialisasi ulang data untuk deteksi perubahan Form Edit
                    formCekEditBillboard = FormHelper.cekFormData($form);

                    $("#modalEditBillboard").modal("show");

                    // Mengecek input keterangan perlu tampil/tidak
                    toggleKeterangan(
                        $("#edit_aktif"),
                        $("#edit_keterangan").closest(".form-group")
                    );
                })
                .fail(function (xhr) {
                    let message =
                        (xhr.responseJSON && xhr.responseJSON.message) ||
                        "Terjadi kesalahan saat mengambil data billboard.";

                    Swal.fire({
                        icon: "error",
                        title: "Gagal memuat data!",
                        text: message,
                    });
                });
        }
    );

    // Tambah Billboard
    $formAddBillboard.validate(
        $.extend(FormHelper.validasiForm(), {
            rules: validasiRule,
            submitHandler: function (form) {
                if (!formCekAddBillboard.isChanged()) return false;
                return FormHelper.submitForm(
                    form,
                    $(form).attr("action"),
                    $(form).find("button[type=submit]"),
                    $(form).find("#btn-loading"),
                    {
                        formCek: formCekAddBillboard,
                        $modalDiv: $("#modalAddBillboard"),
                        $tabelData: $("#tableBillboardList"),
                        $btnClose: $("#modalAddBillboard").find(
                            '[data-dismiss="modal"]'
                        ),
                        $options: {
                            // loadStats: loadStats,
                        },
                    }
                );
            },
        })
    );

    // Edit Billboard
    $formEditBillboard.validate(
        $.extend(FormHelper.validasiForm(), {
            rules: validasiRule,
            submitHandler: function (form) {
                if (!formCekEditBillboard.isChanged()) return false;
                return FormHelper.submitForm(
                    form,
                    $(form).attr("action"),
                    $(form).find("button[type=submit]"),
                    $(form).find("#btn-loading"),
                    {
                        formCek: formCekEditBillboard,
                        $modalDiv: $("#modalEditBillboard"),
                        $tabelData: $("#tableBillboardList"),
                        $btnClose: $("#modalEditBillboard").find(
                            '[data-dismiss="modal"]'
                        ),
                        $options: {
                            // loadStats: loadStats,
                        },
                    }
                );
            },
        })
    );

    // Trigger modal update gambar
    $(document).on(
        "click",
        '#tableBillboardList button[data-target="#modalUpdateGambarBillboard"]',
        function () {
            let id = $(this).data("id");
            let $form = $("#formUpdateGambarBillboard");

            // Mendefinisikan endpoint route dari global window untuk update gambar billboard
            $form.attr("action", window.routes.updateGambar.replace(":id", id));
        }
    );

    // Validasi update gambar
    $formUpdateGambarBillboard.validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                gambar: {
                    required: true,
                    customExtension: "jpg|jpeg|png",
                    customFilesize: 2 * 1024 * 1024, // maksimal 2MB
                },
            },
        })
    );

    // Trigger validasi langsung saat file gambar diubah
    $formUpdateGambarBillboard
        .find('input[name="gambar"]')
        .on("change", function () {
            $(this).valid();
        });

    // Event klik thumbnail
    $(document).on("click", ".billboard-thumb", function () {
        const fullImageUrl = $(this).data("full");
        $("#previewBillboardImage").attr("src", fullImageUrl);
        $("#modalGambarBillboard").modal("show");
    });

    // Tampilkan toast dari session (Laravel)
    let $toast = $("#liveToast");
    if ($toast.length) {
        let toast = new bootstrap.Toast($toast[0]);
        toast.show();
    }

    // Memasukan Fungsi toggleKeterangan ke setiap form
    $("form").each(function () {
        const $form = $(this);
        const $selectAktif = $form.find('select[name="aktif"]');
        const $keterangan = $form
            .find('textarea[name="keterangan"]')
            .closest(".form-group");

        toggleKeterangan($selectAktif, $keterangan);
        $selectAktif.on("change", () =>
            toggleKeterangan($selectAktif, $keterangan)
        );
    });
});
